#define REC_WINDOW 10	
#define LATITUDE_POS 28	
#define OPEN 10000	

struct neighbor {
	char entry[REC_LENGTH];
	double dist;
};

// Helper function to parse float from string manually (device-side compatible)
__device__ float parse_float(const char* str) {
    float result = 0.0f;
    float sign = 1.0f;
    float fraction = 0.0f;
    float divisor = 1.0f;
    int i = 0;
    int has_digit = 0;
    int has_decimal = 0;

    // Skip leading whitespace
    while (str[i] == ' ' || str[i] == '\t') i++;

    // Handle sign
    if (str[i] == '-') {
        sign = -1.0f;
        i++;
    } else if (str[i] == '+') {
        i++;
    }

    // Parse integer part
    while (str[i] >= '0' && str[i] <= '9') {
        result = result * 10.0f + (str[i] - '0');
        i++;
        has_digit = 1;
    }

    // Parse fractional part
    if (str[i] == '.') {
        has_decimal = 1;
        i++;
        while (str[i] >= '0' && str[i] <= '9') {
            divisor *= 10.0f;
            fraction += (str[i] - '0') / divisor;
            i++;
            has_digit = 1;
        }
    }

    if (!has_digit) return 0.0f;

    return sign * (result + fraction);
}

__global__ void compute_distances(const char* elem_9, int x_6, float target_lat, float target_long, float* z) {
    int i = threadIdx.x + blockIdx.x * blockDim.x;
    if (i < x_6) {
        const char* rec_start = elem_9 + (i * REC_LENGTH);
        const char* lat_str = rec_start + LATITUDE_POS - 1;
        const char* lon_str = lat_str + 5; // Latitude is typically 5 chars, longitude follows

        float x_4 = parse_float(lat_str);
        float data_7 = parse_float(lon_str);

        float diff_lat = x_4 - target_lat;
        float diff_long = data_7 - target_long;
        z[i] = sqrtf(diff_lat * diff_lat + diff_long * diff_long);
    }
}

